function cleanJson(value) {
  let s = String(value ?? '').trim();
  s = s.replace(/```json|```/g, '').trim();
  const start = s.indexOf('{');
  const end = s.lastIndexOf('}');
  if (start >= 0 && end > start) s = s.slice(start, end + 1);
  return JSON.parse(s);
}

function isValidEmail(v) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(v || '').trim());
}

const raw = $json.output ?? $json.text ?? $json.response ?? $json.message ?? '';
let data;

try {
  data = cleanJson(raw);
} catch (e) {
  return [{ json: { action: 'normal_chat', output: String(raw || 'Không có nội dung phản hồi.') } }];
}

if (data.action === 'create_email_draft') {
  data = {
    action: 'create_email_drafts',
    emails: [{
      to: data.to || data.email || '',
      recipient_name: data.recipient_name || data.to_name || data.recipient || '',
      subject: data.subject || '',
      body: data.body || data.message || '',
      sender_name: data.sender_name || data.from_name || data.sender || ''
    }],
    need_confirmation: true,
  };
}

if (data.action === 'create_email_drafts') {
  const sourceEmails = Array.isArray(data.emails) ? data.emails : [];

  if (!sourceEmails.length) {
    return [{ json: { action: 'ask_missing_information', message: 'Bạn muốn tạo email draft nhưng chưa có thông tin email nào. Vui lòng cung cấp email người nhận, tên người nhận, tiêu đề, nội dung chính và tên người gửi.' } }];
  }

  const normalized = sourceEmails.map((e, idx) => ({
    index: idx + 1,
    to: String(e.to || e.email || e.recipient_email || '').trim(),
    recipient_name: String(e.recipient_name || e.to_name || e.recipientName || e.recipient || e.name || '').trim(),
    subject: String(e.subject || e.title || '').trim(),
    body: String(e.body || e.content || e.message || '').trim(),
    sender_name: String(e.sender_name || e.from_name || e.senderName || e.sender || '').trim(),
  }));

  const missingLines = [];
  for (const e of normalized) {
    const missing = [];
    if (!e.to) missing.push('email người nhận');
    else if (!isValidEmail(e.to)) missing.push('email người nhận không hợp lệ');
    if (!e.recipient_name) missing.push('tên người nhận');
    if (!e.subject) missing.push('tiêu đề');
    if (!e.body) missing.push('nội dung chính');
    if (!e.sender_name) missing.push('tên người gửi/ký tên');
    if (missing.length) missingLines.push(`Email #${e.index}: thiếu ${missing.join(', ')}`);
  }

  if (missingLines.length) {
    return [{
      json: {
        action: 'ask_missing_information',
        message: 'Mình chưa thể tạo email draft vì còn thiếu thông tin:\n' + missingLines.join('\n') + '\n\nBạn bổ sung giúp mình các thông tin trên nhé.'
      }
    }];
  }

  return [{ json: { action: 'create_email_drafts', emails: normalized, draft_count: normalized.length, need_confirmation: true } }];
}

if (data.action === 'ask_missing_information') {
  return [{ json: { action: 'ask_missing_information', message: data.message || 'Bạn vui lòng bổ sung thêm thông tin.' } }];
}

if (['generate_image', 'generate_images', 'generate_multiple_images'].includes(data.action)) {
  let images = [];
  if (Array.isArray(data.images)) images = data.images;
  else if (Array.isArray(data.items)) images = data.items;
  else if (Array.isArray(data.prompts)) images = data.prompts.map((p, idx) => ({ name: String.fromCharCode(66 + idx), prompt: p }));
  else if (data.prompt || data.message) images = [{ name: 'B', prompt: data.prompt || data.message || '' }];

  images = images.map((img, idx) => ({
    name: img.name || String.fromCharCode(66 + idx),
    prompt: img.prompt || img.message || '',
    send_as_document: Boolean(img.send_as_document ?? data.send_as_document ?? false),
  })).filter(img => img.prompt);

  if (!images.length) {
    return [{ json: { action: 'ask_missing_information', message: 'Bạn muốn tạo ảnh nhưng chưa có mô tả ảnh cần tạo. Vui lòng bổ sung prompt/mô tả ảnh.' } }];
  }

  return [{ json: { action: 'generate_images', images, image_count: images.length, send_as_document: Boolean(data.send_as_document ?? false) } }];
}

if (data.action === 'edit_image') {
  const prompt = String(data.prompt || data.message || '').trim();
  if (!prompt) {
    return [{ json: { action: 'ask_missing_information', message: 'Bạn muốn sửa ảnh nhưng chưa nói rõ cần sửa gì. Vui lòng mô tả phần cần chỉnh sửa.' } }];
  }
  return [{ json: { action: 'edit_image', prompt, send_as_document: Boolean(data.send_as_document ?? false) } }];
}

return [{ json: { action: 'normal_chat', output: data.output || data.message || String(raw) } }];

const emails = $('IF: create drafts?').first().json.emails || [];
let chatId = $('Telegram Trigger').first().json.message.chat.id || '';
try {
  if (!chatId) {
    const root = $('Telegram Trigger').first().json || {};
    const msg = root.message || (root.callback_query && root.callback_query.message) || {};
    chatId = msg.chat && msg.chat.id ? String(msg.chat.id) : '';
  }
} catch (e) {}

const batchId = `${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

return emails.map((e) => ({
  json: {
    chat_id: chatId,
    email_index: e.index,
    to: e.to || '',
    recipient_name: e.recipient_name || '',
    subject: e.subject || '',
    body: e.body || '',
    sender_name: e.sender_name || '',
    batch_id: batchId,
  }
}));

const rows = $input.all().map(i => i.json || {});
let chatId = rows.find(r => r.chat_id)?.chat_id || '';

const emails = rows.map((r, idx) => ({
  index: r.email_index || idx + 1,
  chat_id: r.chat_id || chatId,
  to: r.to_email || r.to || '',
  recipient_name: r.recipient_name || '',
  subject: r.subject || '',
  body: r.body || '',
  sender_name: r.sender_name || '',
  draft_id: r.draft_id || r.id || '',
  batch_id: r.batch_id || '',
}));

return emails.map(e => ({
  json: {
    chat_id: e.chat_id || chatId,
    action: 'created_email_draft',
    draft_count: emails.length,
    index: e.index,
    to: e.to,
    recipient_name: e.recipient_name,
    subject: e.subject,
    body: e.body,
    sender_name: e.sender_name,
    draft_id: e.draft_id,
    batch_id: e.batch_id,
  }
}));

let drafts = $json.drafts || [];

if (typeof drafts === 'string') {
  try { drafts = JSON.parse(drafts); } catch (e) { drafts = []; }
}

if (!Array.isArray(drafts) || !drafts.length) {
  let ids = $json.draft_ids || [];
  if (typeof ids === 'string') {
    try { ids = JSON.parse(ids); } catch (e) { ids = []; }
  }

  drafts = ids.map(id => ({
    chat_id: $json.chat_id || '',
    draft_id: id,
    telegram_message_id: $json.callback_message_id || ''
  }));
}

return drafts.map(d => ({
  json: {
    chat_id: String(d.chat_id || $json.chat_id || ''),
    draft_id: d.draft_id || '',
    email_index: d.email_index || '',
    to_email: d.to_email || '',
    recipient_name: d.recipient_name || '',
    subject: d.subject || '',
    body: d.body || '',
    sender_name: d.sender_name || '',
    batch_id: d.batch_id || '',
    telegram_message_id: String(d.telegram_message_id || $json.callback_message_id || '')
  }
}));

let target = {};
try {
  target = $('Split pending draft_ids').first().json || {};
} catch (e) {}

let callbackMessageId = '';
try {
  callbackMessageId = $('Telegram Trigger').first().json.callback_query?.message?.message_id || '';
} catch (e) {}

const telegramMessageId = target.telegram_message_id || callbackMessageId || '';

return [{
  json: {
    chat_id: String(target.chat_id || ''),
    draft_id: target.draft_id || '',
    telegram_message_id: String(telegramMessageId || ''),
    email_index: target.email_index || '',
    to_email: target.to_email || '',
    recipient_name: target.recipient_name || '',
    subject: target.subject || '',
    body: target.body || '',
    sender_name: target.sender_name || '',
    batch_id: target.batch_id || '',
    sent_count: $input.all().length || 1
  }
}];

