const data = $json || {};

function extractText(obj) {
  if (!obj) return '';

  if (typeof obj === 'string') return obj;

  if (obj.text) return obj.text;
  if (obj.output) return obj.output;

  if (typeof obj.response === 'string') return obj.response;
  if (typeof obj.content === 'string') return obj.content;

  // Gemini app node thường trả dạng: content.parts[0].text
  if (obj.content && Array.isArray(obj.content.parts)) {
    const text = obj.content.parts
      .map(p => extractText(p))
      .filter(Boolean)
      .join('\n');
    if (text) return text;
  }

  // Một số bản trả dạng: parts[0].text
  if (Array.isArray(obj.parts)) {
    const text = obj.parts
      .map(p => extractText(p))
      .filter(Boolean)
      .join('\n');
    if (text) return text;
  }

  // Một số API trả dạng: candidates[0].content.parts[0].text
  if (Array.isArray(obj.candidates)) {
    const text = obj.candidates
      .map(c => extractText(c.content || c))
      .filter(Boolean)
      .join('\n');
    if (text) return text;
  }

  if (obj.response && Array.isArray(obj.response.candidates)) {
    const text = obj.response.candidates
      .map(c => extractText(c.content || c))
      .filter(Boolean)
      .join('\n');
    if (text) return text;
  }

  // Một số LangChain node trả dạng generations[0][0].text
  if (Array.isArray(obj.generations)) {
    const text = obj.generations
      .flat(Infinity)
      .map(g => extractText(g))
      .filter(Boolean)
      .join('\n');
    if (text) return text;
  }

  if (obj.message) return obj.message;

  return '';
}

let message = extractText(data);

message = String(message || '')
  .replace(/\\n/g, '\n')
  .replace(/\*\*/g, '')
  .replace(/```json|```/g, '')
  .replace(/\r/g, '')
  .trim();

if (!message) message = 'Mình chưa đọc được nội dung ảnh.';

return [{
  json: {
    action: 'image_analysis',
    message,
    image_analysis: message
  },
  binary: $binary
}];

